import React, { useState } from "react";
import '../styles/Footer.css';
import styles from '../styles/Content.module.css';

export default function Footer(props){
    return(
        <footer className="footer">
            <table className={styles['standard-table']}>
                <tbody>
                    <tr>
                        <td className={styles['standard-td-10']}>Date: {props.date}</td>
                        <td className={styles['standard-td-5']}>Time: {props.time}</td>
                        <td className={styles['standard-td-15']}>Latittude: {props.lat.toFixed(8)}</td>
                        <td className={styles['standard-td-15']}>Longitude: {props.lon.toFixed(8)}</td>
                    </tr>
                </tbody>
            </table>
        </footer>
    );
}